const data = $input.first().json;

const btcChange = Math.abs(data.bitcoin?.usd_24h_change || 0);
const ethChange = Math.abs(data.ethereum?.usd_24h_change || 0);

const btcAlert = btcChange > 5;
const ethAlert = ethChange > 5;
const hasAlert = btcAlert || ethAlert;

return [{
  json: {
    hasAlert,
    btcPrice: data.bitcoin?.usd,
    btcIls: data.bitcoin?.ils,
    btcChange: data.bitcoin?.usd_24h_change?.toFixed(2),
    btcChangeAbs: btcChange.toFixed(2),
    btcMarketCap: data.bitcoin?.usd_market_cap,
    btcVolume: data.bitcoin?.usd_24h_vol,
    ethPrice: data.ethereum?.usd,
    ethIls: data.ethereum?.ils,
    ethChange: data.ethereum?.usd_24h_change?.toFixed(2),
    ethChangeAbs: ethChange.toFixed(2),
    ethMarketCap: data.ethereum?.usd_market_cap,
    ethVolume: data.ethereum?.usd_24h_vol,
    btcAlert,
    ethAlert,
    timestamp: new Date().toISOString()
  }
}];

const d = $input.first().json;

let alertCoins = [];
if (d.btcAlert) alertCoins.push(`BTC moved ${d.btcChange}%`);
if (d.ethAlert) alertCoins.push(`ETH moved ${d.ethChange}%`);

const subject = `CRYPTO ALERT: ${alertCoins.join(', ')}`;

const body = `<html><body style="font-family: Arial, sans-serif; padding: 20px;">
<h2 style="color: #e74c3c;">Crypto Price Alert</h2>
<p>Significant price movement detected:</p>
<table style="border-collapse: collapse; width: 100%;">
<tr style="background: #f8f9fa;"><th style="padding: 10px; border: 1px solid #dee2e6;">Coin</th><th style="padding: 10px; border: 1px solid #dee2e6;">Price (USD)</th><th style="padding: 10px; border: 1px solid #dee2e6;">Price (ILS)</th><th style="padding: 10px; border: 1px solid #dee2e6;">24h Change</th></tr>
<tr><td style="padding: 10px; border: 1px solid #dee2e6;">Bitcoin</td><td style="padding: 10px; border: 1px solid #dee2e6;">$${Number(d.btcPrice).toLocaleString()}</td><td style="padding: 10px; border: 1px solid #dee2e6;">${Number(d.btcIls).toLocaleString()} ILS</td><td style="padding: 10px; border: 1px solid #dee2e6; color: ${parseFloat(d.btcChange) >= 0 ? 'green' : 'red'};">${d.btcChange}%</td></tr>
<tr><td style="padding: 10px; border: 1px solid #dee2e6;">Ethereum</td><td style="padding: 10px; border: 1px solid #dee2e6;">$${Number(d.ethPrice).toLocaleString()}</td><td style="padding: 10px; border: 1px solid #dee2e6;">${Number(d.ethIls).toLocaleString()} ILS</td><td style="padding: 10px; border: 1px solid #dee2e6; color: ${parseFloat(d.ethChange) >= 0 ? 'green' : 'red'};">${d.ethChange}%</td></tr>
</table>
<p style="color: #888; font-size: 12px;">Alert triggered at ${d.timestamp}</p>
</body></html>`;

return [{ json: { subject, body } }];

const btcChart = $('BTC Weekly Chart Data').first().json;
const ethChart = $('ETH Weekly Chart Data').first().json;
const prices = $('Get Weekly Prices').first().json;

const btcPrices = btcChart.prices || [];
const ethPrices = ethChart.prices || [];

const formatDate = (ts) => new Date(ts).toLocaleDateString('en-IL');

let btcTable = btcPrices.map(p => `<tr><td style="padding:5px;border:1px solid #ddd;">${formatDate(p[0])}</td><td style="padding:5px;border:1px solid #ddd;">$${p[1].toLocaleString(undefined, {maximumFractionDigits:0})}</td></tr>`).join('');
let ethTable = ethPrices.map(p => `<tr><td style="padding:5px;border:1px solid #ddd;">${formatDate(p[0])}</td><td style="padding:5px;border:1px solid #ddd;">$${p[1].toLocaleString(undefined, {maximumFractionDigits:0})}</td></tr>`).join('');

const subject = `Weekly Crypto Summary - ${new Date().toISOString().split('T')[0]}`;

const body = `<html><body style="font-family:Arial,sans-serif;padding:20px;">
<h2>Weekly Crypto Summary</h2>
<h3>Bitcoin (BTC)</h3>
<p>Current: $${Number(prices.bitcoin?.usd).toLocaleString()} | Market Cap: $${Number(prices.bitcoin?.usd_market_cap/1e9).toFixed(1)}B</p>
<table style="border-collapse:collapse;"><tr style="background:#f8f9fa;"><th style="padding:5px;border:1px solid #ddd;">Date</th><th style="padding:5px;border:1px solid #ddd;">Price</th></tr>${btcTable}</table>
<h3>Ethereum (ETH)</h3>
<p>Current: $${Number(prices.ethereum?.usd).toLocaleString()} | Market Cap: $${Number(prices.ethereum?.usd_market_cap/1e9).toFixed(1)}B</p>
<table style="border-collapse:collapse;"><tr style="background:#f8f9fa;"><th style="padding:5px;border:1px solid #ddd;">Date</th><th style="padding:5px;border:1px solid #ddd;">Price</th></tr>${ethTable}</table>
<p style="color:#888;font-size:12px;">Generated ${new Date().toISOString()}</p>
</body></html>`;

return [{ json: { subject, body } }];
